import '../lib/patch.dart';
import '../lib/profile_store.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  final patch = ProfilePatch.fromJson({'note': null});
  final store = ProfileStore(
    const Profile(displayName: 'Lin', note: 'Temporary'),
  );
  store.apply(patch);

  check(store.current.displayName == 'Lin', 'omitted display name changed');
  check(store.current.note == null, 'note was not cleared');

  final encoded = patch.toJson();
  check(!encoded.containsKey('displayName'), 'omitted field was serialized');
  check(encoded.containsKey('note'), 'explicit clear disappeared on serialization');
  check(encoded['note'] == null, 'serialized clear was not null');
}
